#!/usr/bin/env node
const fs = require('fs');
const path = require('path');

const page = Buffer.from("", "base64").toString("utf8");
const client = Buffer.from("", "base64").toString("utf8");

const jobsDir = path.join(__dirname, "app", "en", "jobs");

fs.writeFileSync(path.join(jobsDir, "page.tsx"), page);
console.log("✓ page.tsx written");

fs.writeFileSync(path.join(jobsDir, "MandatesClient.tsx"), client);
console.log("✓ MandatesClient.tsx written");

console.log("\nDone. Run: git add . && git commit -m \"EP Mandate Pages v4\" && git push");
